import React, { useMemo, useState } from 'react';
import { View, Text, TextInput, TouchableOpacity, Alert, StyleSheet } from 'react-native';
import { useNavigate } from 'react-router-dom';
import { createUserWithEmailAndPassword, signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../../src/config/firebase';
import { SoundManager } from '../sound';
import { useTheme } from '../theme';
import { useAuth } from './AuthContext';

export default function LoginScreen() {
  const { colors, onPrimary } = useTheme();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [loading, setLoading] = useState(false);

  // 既にログイン済みの場合はホームへリダイレクト
  React.useEffect(() => {
    if (user) {
      navigate('/');
    }
  }, [user, navigate]);

  const isRegisterMode = mode === 'register';
  const title = isRegisterMode ? '新規登録' : 'ログイン';

  const canSubmit = useMemo(() => {
    return email.trim().length > 0 && password.trim().length > 0;
  }, [email, password]);

  const getAuthErrorMessage = (error: any) => {
    const code = error?.code as string | undefined;

    switch (code) {
      case 'auth/invalid-email':
        return 'メールアドレスの形式が正しくありません。';
      case 'auth/user-not-found':
        return 'このメールアドレスのアカウントは見つかりません。';
      case 'auth/wrong-password':
      case 'auth/invalid-credential':
        return 'メールアドレスまたはパスワードが正しくありません。';
      case 'auth/email-already-in-use':
        return 'このメールアドレスは既に登録されています。';
      case 'auth/weak-password':
        return 'パスワードは6文字以上で入力してください。';
      case 'auth/missing-password':
        return 'パスワードを入力してください。';
      case 'auth/too-many-requests':
        return '試行回数が多すぎます。少し時間をおいて再試行してください。';
      default:
        return '認証に失敗しました。入力内容を確認してもう一度お試しください。';
    }
  };

  const handleSubmit = async () => {
    if (!canSubmit || loading) return;

    try {
      setLoading(true);
      SoundManager.play('decide');

      if (isRegisterMode) {
        await createUserWithEmailAndPassword(auth, email.trim(), password);
        Alert.alert('登録完了', 'アカウントを作成しました。ホームへ移動します。');
        navigate('/');
        return;
      }

      await signInWithEmailAndPassword(auth, email.trim(), password);
      Alert.alert('ログイン成功', 'ようこそ。学習を始めましょう。');
      navigate('/');
    } catch (e: any) {
      console.error('LoginScreen error:', e);
      Alert.alert('認証エラー', getAuthErrorMessage(e));
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={[styles.screen, { backgroundColor: colors.background }]}>
      <View style={[styles.card, { backgroundColor: colors.card, borderColor: colors.border }]}>
        <Text style={[styles.title, { color: colors.text }]}>{title}</Text>
        <Text style={[styles.subtitle, { color: colors.textSecondary }]}>学習データを安全に保存して、どこでも続きから学べます。</Text>

        <Text style={[styles.label, { color: colors.text }]}>メールアドレス</Text>
        <TextInput
          value={email}
          onChangeText={setEmail}
          placeholder="example@mail.com"
          keyboardType="email-address"
          autoCapitalize="none"
          autoCorrect={false}
          style={[styles.input, { borderColor: colors.border, color: colors.text, backgroundColor: colors.background }]}
          placeholderTextColor={colors.textSecondary}
        />

        <Text style={[styles.label, { color: colors.text }]}>パスワード</Text>
        <TextInput
          value={password}
          onChangeText={setPassword}
          placeholder="6文字以上のパスワード"
          secureTextEntry
          style={[styles.input, { borderColor: colors.border, color: colors.text, backgroundColor: colors.background }]}
          placeholderTextColor={colors.textSecondary}
        />

        <TouchableOpacity
          onPress={handleSubmit}
          disabled={!canSubmit || loading}
          style={[
            styles.primaryButton,
            { backgroundColor: !canSubmit || loading ? colors.border : colors.primary }
          ]}
        >
          <Text style={[styles.primaryButtonText, { color: !canSubmit || loading ? colors.textSecondary : onPrimary }]}>
            {loading ? '処理中...' : isRegisterMode ? '新規登録する' : 'ログインする'}
          </Text>
        </TouchableOpacity>

        <TouchableOpacity
          onPress={() => setMode((m) => (m === 'login' ? 'register' : 'login'))}
          style={styles.toggleButton}
        >
          <Text style={[styles.toggleText, { color: colors.primary }]}>
            {isRegisterMode ? 'すでにアカウントをお持ちの方はこちら' : 'アカウントを作成する'}
          </Text>
        </TouchableOpacity>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  screen: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    paddingHorizontal: 20,
    paddingVertical: 24,
  },
  card: {
    width: '100%',
    maxWidth: 440,
    borderWidth: 1,
    borderRadius: 20,
    paddingHorizontal: 20,
    paddingVertical: 24,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.06,
    shadowRadius: 10,
    elevation: 2,
  },
  title: {
    fontSize: 28,
    fontWeight: '700',
    marginBottom: 8,
  },
  subtitle: {
    fontSize: 14,
    lineHeight: 22,
    marginBottom: 18,
  },
  label: {
    fontSize: 14,
    fontWeight: '600',
    marginBottom: 6,
  },
  input: {
    borderWidth: 1,
    borderRadius: 14,
    paddingHorizontal: 14,
    paddingVertical: 12,
    marginBottom: 14,
    fontSize: 15,
  },
  primaryButton: {
    borderRadius: 14,
    paddingVertical: 14,
    alignItems: 'center',
    marginTop: 4,
  },
  primaryButtonText: {
    fontSize: 16,
    fontWeight: '700',
  },
  toggleButton: {
    alignItems: 'center',
    paddingTop: 14,
    paddingBottom: 2,
  },
  toggleText: {
    fontSize: 14,
    fontWeight: '600',
  },
});

